{% extends 'cattletrace/base.html' %}

{% block title %}Welcome — CattleTrace{% endblock %}

{% block content %}
<section class="hero">
    <h1>Welcome to CattleTrace</h1>
    <p>This is the landing page. Use the navigation to explore the application.</p>
    {% if user.is_authenticated %}
        <p>Go to your <a href="{% url 'CattleTrace:dashboard' %}">dashboard</a>.</p>
    {% else %}
        <p><a href="{% url 'CattleTrace:login' %}">Log in</a> or <a href="{% url 'CattleTrace:register' %}">register</a> to get started.</p>
    {% endif %}
</section>

{% endblock %}
